import unittest
from unittest.mock import patch

from incident import api
from incident import service


class IncidentOwnerServiceTests(unittest.TestCase):
    @patch("incident.service.repository.get_incident")
    def test_build_incident_summary_projects_only_id_and_owner(self, get_incident):
        get_incident.return_value = {
            "id": "INC-42",
            "owner": "operations",
            "status": "open",
            "title": "Example incident",
        }

        result = service.build_incident_summary("INC-42")

        self.assertEqual(result, {"id": "INC-42", "owner": "operations"})
        get_incident.assert_called_once_with("INC-42")

    @patch("incident.service.repository.get_incident", return_value=None)
    def test_build_incident_summary_signals_missing_incident(self, get_incident):
        with self.assertRaises(KeyError) as error:
            service.build_incident_summary("INC-404")

        self.assertEqual(error.exception.args, ("INC-404",))
        get_incident.assert_called_once_with("INC-404")


class IncidentOwnerApiTests(unittest.TestCase):
    @patch("incident.api.build_incident_summary")
    def test_handler_returns_exact_owner_response_for_known_incident(
        self, build_incident_summary
    ):
        build_incident_summary.return_value = {
            "id": "INC-42",
            "owner": "operations",
        }

        result = api.get_incident_summary("INC-42")

        self.assertEqual(
            result,
            {
                "status": 200,
                "body": {"id": "INC-42", "owner": "operations"},
            },
        )
        build_incident_summary.assert_called_once_with("INC-42")

    @patch("incident.api.build_incident_summary", side_effect=KeyError("INC-404"))
    def test_handler_returns_stable_not_found_response(self, build_incident_summary):
        result = api.get_incident_summary("INC-404")

        self.assertEqual(
            result,
            {
                "status": 404,
                "body": {"error": "incident not found"},
            },
        )
        build_incident_summary.assert_called_once_with("INC-404")


if __name__ == "__main__":
    unittest.main()

