from incident.service import build_incident_summary


INCIDENT_OWNER_ROUTE = "/incident-owner/:incident_id"
ROUTES = {
    ("GET", INCIDENT_OWNER_ROUTE): "get_incident_summary",
}


def get_incident_summary(incident_id):
    try:
        body = build_incident_summary(incident_id)
    except KeyError:
        return {
            "status": 404,
            "body": {"error": "incident not found"},
        }
    return {
        "status": 200,
        "body": body,
    }


def handle_request(method, path):
    route_prefix = "/incident-owner/"
    if method == "GET" and path.startswith(route_prefix):
        incident_id = path[len(route_prefix):]
        if incident_id and "/" not in incident_id:
            return get_incident_summary(incident_id)

    return {
        "status": 404,
        "body": {"error": "not found"},
    }

